from flask import Flask, request, jsonify
from prometheus_client import start_http_server, Counter, Histogram

app = Flask(__name__)

# Define Prometheus metrics
REQUEST_COUNT = Counter('api_request_count', 'Total number of requests', ['method', 'endpoint', 'user_id', 'api_key'])
REQUEST_LATENCY = Histogram('api_request_latency_seconds', 'Request latency in seconds', ['method', 'endpoint'])

@app.route('/metrics')
def metrics():
    start_http_server(8000)
    return jsonify({'message': 'Prometheus metrics endpoint'})

@app.route('/api', methods=['POST'])
def api():
    user_id = request.headers.get('X-User-ID')
    api_key = request.headers.get('X-API-Key')
    
    REQUEST_COUNT.labels(request.method, '/api', user_id, api_key).inc()
    
    with REQUEST_LATENCY.time():
        # Simulate API processing time
        response = {
            'message': 'API processed successfully'
        }
    
    return jsonify(response)

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)